-- ═══════════════════════════════════════════════════════════════════════════════
-- Donkey Kong Country 2.lua — game module for the Archipelago BizHawk connector.
--                          Donkey Kong Country 2: Diddy's Kong Quest (SNES)
--
-- STATUS: COMMUNITY world. location DETECTION + goal are REAL and SOURCE-DERIVED
-- from the official apworld worlds/dkc2 (Client.py game_watcher + Locations.py +
-- Levels.py, TheLX5/Archipelago @ branch `dkc2`, world_version 3.1.2). The
-- 581-entry location table was GENERATED by JOINING Locations.all_locations
-- (name → AP id) with Levels.location_id_to_level_id (name → [loc_type, level_num,
-- data]) — not hand-copied — so every (AP id → level_num/index) pair is exact.
-- Mock-verified through MoonSharp against synthetic WRAM/SRAM/CARTROM. Loads
-- crash-free on any ROM; self-disables on a non-AP cartridge.
--
-- SOURCE: https://github.com/TheLX5/Archipelago  (branch `dkc2`, worlds/dkc2)
--         game string "Donkey Kong Country 2", patch_suffix ".apdkc2",
--         items_handling 0b111 (FULL remote), base ROM US REV1
--         MD5 d323e6bb4ccc85fd7b416f58350bc1a2 (HASH_US_REV_1; the patch's
--         declared `hash`). The vanilla US 1.0 dump hashes
--         98458530599b9dff8a7414a7f20b777a (HASH_US).
--
-- MEMORY MODEL (SNI → BizHawk)  — see Research_V2/SNES_BRIDGE_2026-06-12.md
-- ──────────────────────────────────────────────────────────────────────────
--   The dkc2 client is an SNIClient. Its SNI addresses translate to BizHawk SNES
--   memory domains. DKC2 — unlike DKC1 — reads from THREE regions:
--     SNI WRAM_START(0xF50000)+off → domain "WRAM",    offset off  (= $7E0000+off)
--     SNI SRAM_START(0xE00000)+off → domain "CARTRAM", offset off  (battery SRAM;
--                                    fallback "SRAM")
--     SNI ROM_START(0x000000)+off  → domain "CARTROM", offset off  (raw ROM file
--                                    offset. Fallbacks "ROM"/"System Bus")
--   DKC2 is a HiROM cartridge, so the internal header at SNES $00:FFC0 lives at
--   ROM **file** offset 0xFFC0 (HiROM places the header there — NOT the LoROM
--   0x7FC0). The client read (DKC2_ROMHASH_START = 0xFFC0) and the AP patch write
--   (patch.write_bytes(0xFFC0, name) — name begins "DKC2") both use file offset
--   0xFFC0, so this module reads the signature from CARTROM 0xFFC0 directly.
--
--   The client (DKC2Memory enum) reads, and this module mirrors:
--     • general_data = Read(WRAM+0x00D0, 0x10) → WRAM
--         loaded_save = u16 LE at WRAM 0x00D5 (general_data[0x05:0x07]); ==0 → no save
--     • nmi_pointer  = Read(WRAM+0x0020, 0x02) → WRAM, u16 LE
--                      (0x8CE9 or 0x8CF1 == in a map / transition)
--     • validation   = Read(DKC2_INIT_FLAG = SRAM+0x822, 0x02) → CARTRAM, u16 LE
--                      (must == 0xDEAD; the basepatch sets it once running)
--     • current_level= Read(WRAM+0x08A8, 0x01) → WRAM
--     • loaded_level = Read(WRAM+0x00D3, 0x01) → WRAM
--     • current_map  = Read(WRAM+0x06B1, 0x01) → WRAM
--     • brightness   = Read(WRAM+0x0512, 0x01) → WRAM (& 0x0F == 0x0F = full)
--     • game_flags   = Read(WRAM+0x59B2, 0x60) → WRAM
--         bonus_flags   = game_flags[0x00:0x20]   (level bonus bitfield)
--         dk_coin_flags = game_flags[0x20:0x40]   (DK-coin bitfield)
--         stage_flags   = game_flags[0x40:0x60]   (level-clear bitfield)
--     • misc_flags   = Read(WRAM+0x08D2, 0x80) → WRAM   (kong_flags = misc[0x30])
--     • swanky_flags = Read(WRAM+0x08F0, 0x09) → WRAM
--     • sanity_flags = Read(WRAM+0x1FF00, 0x100) → WRAM (coin/bunch/balloon bits)
--     • settings     = Read(DKC2_SETTINGS = CARTROM 0x3DFF80, 0x40) → CARTROM
--         settings[0x01] = selected_goal
--         settings[0x20..0x25] = per-check-family enable bytes (see below)
--   IDENTITY / VALIDATION (mirrors validate_rom + the game_watcher 0xDEAD gate):
--     ROM header at CARTROM 0xFFC0 begins with "DKC2" and is not all-zero, AND
--     the runtime init flag at CARTRAM 0x822 reads 0xDEAD. The AP basepatch bakes
--     in the header and arms the init flag.
--
-- HOW DKC2 CHECKS WORK (mirrors Client.py game_watcher; per-location loc_type)
--   Each location carries {loc_type, level_num, data}. game_watcher only processes
--   a location while NOT in a map/transition (nmi_pointer != 0x8CE9/0x8CF1) AND at
--   full brightness (brightness & 0x0F == 0x0F). For the level-indexed bitfields it
--   computes:  level_offset = (level_num >> 3) & 0x1E ; level_bit = 1<<(level_num & 0x0F)
--   then reads a u16 LE word at flagarray[level_offset:level_offset+2]:
--     0x00 Level clear : stage_flags  word & level_bit
--     0x01 KONG        : level_num == current_level AND kong_flags & 0x0F == 0x0F   [gated kong_as_checks]
--     0x02 DK Coin     : dk_coin_flags word & level_bit                            [gated dk_coins_as_checks]
--     0x03 Bonus       : bonus_flags  word & level_bit
--     0x04 Swanky      : swanky_flags[level_num>>4] & (level_num & 0x07)            [gated swanky_as_checks]
--     0x05 Banana Coin : level_num == loaded_level AND sanity_flags[data] & 0x02   [gated coins_as_checks]
--     0x06 Banana Bunch: level_num == loaded_level AND sanity_flags[data] & 0x04   [gated bunches_as_checks]
--     0x07 Balloon     : level_num == loaded_level AND sanity_flags[data] & 0x01   [gated balloons_as_checks]
--   The five *_as_checks gates are per-seed CARTROM settings bytes
--   (settings[0x20..0x25]). DKC2 shares one set of flag arrays across check
--   families, so — unlike DKC1 — the gate matters: e.g. a level's bonus word also
--   backs DK-coin reads, and the KONG bit is a live player flag. We therefore read
--   the gates from CARTROM and apply them exactly as game_watcher does, so a
--   disabled family is never mis-reported. (Level-clear and Bonus are never gated.)
--
-- WHAT THIS DOES
--   • poll(): the game_watcher location scan above → AP location ids, gated to the
--     slot's server location set, to the per-family settings gates, and to the
--     in-game state (game_state set once a save is loaded and the player has
--     reached the map, i.e. nmi_pointer has read 0x8CE9/0x8CF1 at least once).
--   • is_goal_complete(): mirrors game_watcher's goal block — selected_goal =
--     settings[0x01]; goal_check bit 1 = bonus_flags level 0x61 set, bit 2 =
--     dk_coin_flags level 0x6B set; complete when goal_check & selected_goal ==
--     selected_goal. (Bit 1 = K. Rool defeated / The Flying Krock; bit 2 = Lost
--     World / Krocodile Core DK-coin — together they cover the "beat K. Rool",
--     "Lost World", and "both" goal options the server bakes into settings[0x01].)
--   • receive_item(): NO-OP (documented). items_handling = 0b111 (FULL remote) —
--     the dkc2 client owns ALL item delivery via an intricate, heavily-state-gated
--     set of SRAM/WRAM writes (kong-unlock bitmask, ability/animal/object unlock
--     bytes at SRAM offsets, currency increments, trap counters, an SFX strobe via
--     DKC2_SOUND_PLAYBACK, plus a recv-index handshake at DKC2_RECV_INDEX, all
--     gated on full brightness; EnergyLink DK barrels / TrapLink / DeathLink /
--     SharedDamage on top). That delivery path is the one piece that needs in-
--     emulator verification before it is wired, so it is left out rather than
--     shipped unverified (a wrong write would corrupt the save or desync the
--     recv-index). Checks + goal above are fully functional regardless.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "Donkey Kong Country 2"

local ADDRESSES_VERIFIED = true   -- table generated from worlds/dkc2 source

-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTRAM = "CARTRAM"     -- battery SRAM in BizHawk; fallback "SRAM"
local CARTROM = "CARTROM"     -- SNES cartridge ROM in BizHawk; fallbacks below

-- ── Addresses / constants (worlds/dkc2/Client.py module top) ──────────────────
-- Expressed as BizHawk-domain offsets (already net of WRAM_START/SRAM_START/ROM_START).
local GENERAL_DATA_OFF  = 0x00D0      -- WRAM: 0x10 block; loaded_save = u16 LE at +0x05
local NMI_POINTER_OFF   = 0x0020      -- WRAM: u16 LE; == 0x8CE9/0x8CF1 while in a map
local VALIDATION_OFF    = 0x0822      -- CARTRAM: u16 LE init flag; must == 0xDEAD
local CURRENT_LEVEL_OFF = 0x08A8      -- WRAM: id of the level currently being played
local LOADED_LEVEL_OFF  = 0x00D3      -- WRAM: loaded level id (sanity checks key on it)
local CURRENT_MAP_OFF   = 0x06B1      -- WRAM: current overworld map id
local BRIGHTNESS_OFF    = 0x0512      -- WRAM: screen brightness; & 0x0F == 0x0F = full
local GAME_FLAGS_OFF    = 0x59B2      -- WRAM: base of the 0x60-byte game-flag block
local MISC_FLAGS_OFF    = 0x08D2      -- WRAM: base of the 0x80-byte misc-flag block
local SWANKY_FLAGS_OFF  = 0x08F0      -- WRAM: base of the swanky (quiz) flag block
local SANITY_FLAGS_OFF  = 0x1FF00     -- WRAM: base of the 0x100-byte sanity-flag array
local SETTINGS_OFF      = 0x3DFF80    -- CARTROM: base of the 0x40-byte settings block
local ROMHASH_OFF       = 0xFFC0      -- CARTROM: ROM-header title; first 4 = "DKC2"

-- Sub-offsets within blocks.
local LOADED_SAVE_SUB   = 0x05        -- general_data[0x05:0x07] = loaded_save (u16 LE)
local KONG_FLAG_SUB     = 0x30        -- misc_flags[0x30] = kong_flags
local BONUS_BASE        = 0x00        -- game_flags[0x00:0x20] = bonus_flags
local DKCOIN_BASE       = 0x20        -- game_flags[0x20:0x40] = dk_coin_flags
local STAGE_BASE        = 0x40        -- game_flags[0x40:0x60] = stage_flags (level clear)

-- Settings byte indices (CARTROM, settings[i]).
local SET_GOAL          = 0x01        -- selected_goal
local SET_DKCOIN        = 0x20        -- dk_coins_as_checks
local SET_KONG          = 0x21        -- kong_as_checks
local SET_BALLOON       = 0x22        -- balloons_as_checks
local SET_COIN          = 0x23        -- coins_as_checks
local SET_BUNCH         = 0x24        -- bunches_as_checks
local SET_SWANKY        = 0x25        -- swanky_as_checks

-- Sentinel values.
local IN_MAP_NMI_A      = 0x8CE9      -- nmi_pointer value while on the world map
local IN_MAP_NMI_B      = 0x8CF1      -- second in-map nmi_pointer value
local VALIDATED         = 0xDEAD      -- validation flag value when the basepatch is live

-- Per-location loc_type tags (Client.py game_watcher).
local T_CLEAR    = 0x00
local T_KONG     = 0x01
local T_DKCOIN   = 0x02
local T_BONUS    = 0x03
local T_SWANKY   = 0x04
local T_COIN     = 0x05
local T_BUNCH    = 0x06
local T_BALLOON  = 0x07

-- Goal flag positions (game_watcher goal block).
local GOAL_BONUS_LEVEL  = 0x61        -- bonus_flags level checked → goal bit 1
local GOAL_DKCOIN_LEVEL = 0x6B        -- dk_coin_flags level checked → goal bit 2

