-- ── Internal state ────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil    -- cached "DKC2" header result
local game_state       = false  -- true once a save is loaded and the map reached
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[dkc2] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8  = memory.read_u8     or memory.readbyte
  mem.read_u16 = memory.read_u16_le or memory.readword
  return mem.read_u8 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_wram_u8(off)   return rd(mem.read_u8,  off, WRAM) end
local function read_wram_u16(off)  return rd(mem.read_u16, off, WRAM) end

-- CARTRAM (battery SRAM) reads with a "SRAM" domain-name fallback.
local function read_cartram_u16(off)
  local ok, v = pcall(mem.read_u16, off, CARTRAM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u16, off, "SRAM")
  if ok and type(v) == "number" then return v end
  return nil
end

-- CARTROM reads with "ROM" / "System Bus" domain-name fallbacks (cores vary;
-- the raw-file-offset CARTROM/ROM form is what every SNES BizHawk core exposes).
local function read_cartrom_u8(off)
  local ok, v = pcall(mem.read_u8, off, CARTROM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "ROM")
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "System Bus")
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  -- 16-bit safe AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: the SNES header title starts with "DKC2" (validate_rom) ──────
-- validate_rom also rejects an all-zero hash; a real "DKC2" prefix already
-- excludes that, so the prefix check is sufficient here.
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local sig = "DKC2"
  for i = 1, #sig do
    local b = read_cartrom_u8(ROMHASH_OFF + i - 1)
    if b == nil then return false end          -- not readable yet; retry next poll
    if b ~= string.byte(sig, i) then
      rom_ok = false
      log("non-DKC2 ROM (no 'DKC2' header) — detection idle, no reports")
      return false
    end
  end
  rom_ok = true
  log("DKC2 ROM verified ('DKC2' header title present)")
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- ── Per-poll snapshots (read once per poll, matching game_watcher) ────────────
local snap = {}     -- the RAM the client reads, refreshed each poll

local function read_region_wram(off, len)
  local t = {}
  for i = 0, len - 1 do t[i] = read_wram_u8(off + i) end
  return t
end

-- u16 LE from a WRAM byte table at index i (matches int.from_bytes(arr[i:i+2],"little")).
local function word_le(tbl, i)
  local lo = tbl[i]
  local hi = tbl[i + 1]
  if lo == nil or hi == nil then return nil end
  return lo + hi * 256
end

local function refresh_snapshot()
  local gd            = read_region_wram(GENERAL_DATA_OFF, 0x10)
  snap.loaded_save    = word_le(gd, LOADED_SAVE_SUB)
  snap.nmi_pointer    = read_wram_u16(NMI_POINTER_OFF)
  snap.validation     = read_cartram_u16(VALIDATION_OFF)
  snap.current_level  = read_wram_u8(CURRENT_LEVEL_OFF)
  snap.loaded_level   = read_wram_u8(LOADED_LEVEL_OFF)
  snap.brightness     = read_wram_u8(BRIGHTNESS_OFF)
  local game_flags    = read_region_wram(GAME_FLAGS_OFF, 0x60)
  snap.game_flags     = game_flags
  local misc          = read_region_wram(MISC_FLAGS_OFF, 0x80)
  snap.kong_flags     = misc[KONG_FLAG_SUB]
  snap.swanky_flags   = read_region_wram(SWANKY_FLAGS_OFF, 0x09)
  snap.sanity_flags   = read_region_wram(SANITY_FLAGS_OFF, 0x100)
end

-- Settings are read from CARTROM once (they are baked into the patched ROM).
local settings_cache = nil
local function settings_byte(idx)
  if settings_cache == nil then settings_cache = {} end
  if settings_cache[idx] == nil then
    settings_cache[idx] = read_cartrom_u8(SETTINGS_OFF + idx)
  end
  return settings_cache[idx]
end

-- full brightness == 0x0F in the low nibble (game_watcher gate).
local function full_brightness()
  return snap.brightness ~= nil and bit_and(snap.brightness, 0x0F) == 0x0F
end

-- in a map / transition? game_watcher skips location processing while here.
local function in_map()
  return snap.nmi_pointer ~= nil
     and (snap.nmi_pointer == IN_MAP_NMI_A or snap.nmi_pointer == IN_MAP_NMI_B)
end

-- A level-indexed bitfield word read (mirrors game_watcher's offset/bit math).
-- base = byte offset into game_flags of the desired sub-array.
local function level_word(base, level_num)
  local level_offset = bit_and(math.floor(level_num / 8), 0x1E)   -- (level_num>>3)&0x1E
  return word_le(snap.game_flags, base + level_offset)
end
local function level_bit(level_num)
  return 2 ^ (level_num % 16)                                     -- 1<<(level_num&0x0F)
end

-- ── One location's "checked?" test (mirrors game_watcher per loc_type) ────────
-- Returns true only when the location is satisfied AND its per-family settings
-- gate (if any) is enabled — exactly as game_watcher's elif chain decides.
local function location_checked(loc_type, level_num, data)
  if loc_type == T_CLEAR then
    local w = level_word(STAGE_BASE, level_num)
    return w ~= nil and bit_and(w, level_bit(level_num)) ~= 0

  elseif loc_type == T_KONG then
    if (settings_byte(SET_KONG) or 0) == 0 then return false end
    if snap.current_level ~= level_num then return false end
    return snap.kong_flags ~= nil and bit_and(snap.kong_flags, 0x0F) == 0x0F

  elseif loc_type == T_DKCOIN then
    if (settings_byte(SET_DKCOIN) or 0) == 0 then return false end
    local w = level_word(DKCOIN_BASE, level_num)
    return w ~= nil and bit_and(w, level_bit(level_num)) ~= 0

  elseif loc_type == T_BONUS then
    local w = level_word(BONUS_BASE, level_num)
    return w ~= nil and bit_and(w, level_bit(level_num)) ~= 0

  elseif loc_type == T_SWANKY then
    if (settings_byte(SET_SWANKY) or 0) == 0 then return false end
    -- bonus_offset = level_num>>4 ; bonus_bit = level_num & 0x07 (game_watcher).
    local bonus_offset = math.floor(level_num / 16)
    local bonus_bit    = level_num % 8
    local f = snap.swanky_flags[bonus_offset]
    return f ~= nil and bit_and(f, bonus_bit) ~= 0

  elseif loc_type == T_COIN then
    if (settings_byte(SET_COIN) or 0) == 0 then return false end
    if snap.loaded_level ~= level_num or data == nil then return false end
    local f = snap.sanity_flags[data]
    return f ~= nil and bit_and(f, 0x02) == 0x02

  elseif loc_type == T_BUNCH then
    if (settings_byte(SET_BUNCH) or 0) == 0 then return false end
    if snap.loaded_level ~= level_num or data == nil then return false end
    local f = snap.sanity_flags[data]
    return f ~= nil and bit_and(f, 0x04) == 0x04

  elseif loc_type == T_BALLOON then
    if (settings_byte(SET_BALLOON) or 0) == 0 then return false end
    if snap.loaded_level ~= level_num or data == nil then return false end
    local f = snap.sanity_flags[data]
    return f ~= nil and bit_and(f, 0x01) == 0x01
  end
  return false
end

-- ── Detection gate ────────────────────────────────────────────────────────────
-- game_watcher requires: a loaded save (loaded_save != 0), the runtime init flag
-- == 0xDEAD, and it latches game_state once nmi_pointer reads an in-map value.
-- We mirror that: game_state turns true on the first in-map read while validated.
local function update_game_state()
  if snap.loaded_save == nil or snap.loaded_save == 0 then
    game_state = false
    return false
  end
  if snap.validation ~= VALIDATED then
    -- ROM hash already matched "DKC2"; the runtime flag just isn't armed yet.
    game_state = false
    return false
  end
  if in_map() then game_state = true end
  return game_state
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " location flags (items_handling=0b111; receive_item is a "
      .. "documented no-op pending in-emulator verification)")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  refresh_snapshot()
  if not update_game_state() then return new end
  -- game_watcher breaks out of the location loop while in a map or not at full
  -- brightness; mirror that exactly so a transition never mis-reports.
  if in_map() or not full_brightness() then return new end
  for ap_id, ld in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id)
       and location_checked(ld[1], ld[2], ld[3]) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  refresh_snapshot()
  if snap.game_flags == nil then return false end
  local selected_goal = settings_byte(SET_GOAL)
  if selected_goal == nil or selected_goal == 0 then return false end
  -- goal_check bit 1: bonus_flags level 0x61 set; bit 2: dk_coin_flags level 0x6B.
  local goal_check = 0
  local wb = level_word(BONUS_BASE, GOAL_BONUS_LEVEL)
  if wb ~= nil and bit_and(wb, level_bit(GOAL_BONUS_LEVEL)) ~= 0 then
    goal_check = goal_check + 1
  end
  local wd = level_word(DKCOIN_BASE, GOAL_DKCOIN_LEVEL)
  if wd ~= nil and bit_and(wd, level_bit(GOAL_DKCOIN_LEVEL)) ~= 0 then
    goal_check = goal_check + 2
  end
  -- complete when (goal_check & selected_goal) == selected_goal.
  return bit_and(goal_check, selected_goal) == selected_goal
end

-- Remote multiworld items: see the file header. items_handling = 0b111 (FULL
-- remote) means the dkc2 client owns ALL item delivery — kong-unlock bitmask,
-- ability/animal/object unlock bytes at SRAM offsets, currency increments, trap
-- counters, an SFX strobe, a recv-index handshake at DKC2_RECV_INDEX, plus
-- EnergyLink DK barrels / TrapLink / DeathLink / SharedDamage, all heavily gated
-- on game state and full brightness. That path is the one piece deferred until it
-- can be confirmed in-emulator. No-op (never a wrong write) until then; checks +
-- goal above are fully functional.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
